            $script:callCount = 0
            Get-AllPosts -Limit 2 | Out-Null
            # Should have made 3 calls: page 1 (2 items), page 2 (1 item), page 3 (empty)
            Should -Invoke Invoke-RestMethod -Times 3 -Exactly
        }
    }
}

